package be.schaubroeck.lpb.rkm.rekenmotor.feestdagen;

import be.schaubroeck.lpb.ConfigConstants;
import be.schaubroeck.lpb.rkm.feestdagen.VergoedingFeestDagResultaat;
import be.schaubroeck.lpb.rkm.feestdagen.VergoedingFeestdagService;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.service.AdminService;
import be.schaubroeck.lpb.tools.service.OpdrachtService;
import be.schaubroeck.temporal.interval.Month;
import be.schaubroeck.temporal.util.TemporalContext;
import be.schaubroeck.util.launch.StandaloneMainHelper;
import com.google.common.collect.Lists;
import lombok.extern.slf4j.Slf4j;
import org.joda.time.LocalDate;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.context.support.ClassPathXmlApplicationContext;

import java.util.Calendar;
import java.util.List;

@Slf4j
public class VergoedingFeestDagMain {

    static {
        StandaloneMainHelper.initialize("rekenmotor-vergoeding-feestdag", ConfigConstants.LOG4J_SERVER);
    }


    /**
     * @param args
     */
    public static void main(String[] args) {
    /*    Integer adminid = Integer.valueOf(args[0]);
        Integer persoonId = Integer.valueOf(args[1]);
        Integer opdrachtNr = Integer.valueOf(args[2]);
        Integer referteJaar = Integer.valueOf(args[3]);*/

        int adminid = 1447;
        int persoonId = 130;
        int opdrachtNr = 1;
        LocalDate referteDatum = new LocalDate(2021, 5, 1);

        log.info("Berekening Vergoeding Feestdag voor adminid {}, persoonid-opdrachtnummer {}-{} en referteDatum {}", adminid, persoonId, opdrachtNr, referteDatum);

        try (ClassPathXmlApplicationContext context = new ClassPathXmlApplicationContext(ConfigConstants.SERVER_BUNDLE)) {
            VergoedingFeestDagMain main = (VergoedingFeestDagMain) context.getBean("vergoedingFeestDagMain");
            long startTimeMillis = Calendar.getInstance().getTimeInMillis();
            main.test(adminid, persoonId, opdrachtNr, referteDatum);
            //main.testAll(adminid, referteDatum);
            long endTimeMillis = Calendar.getInstance().getTimeInMillis();
            log.info("Duur: {} seconden", (endTimeMillis - startTimeMillis) / 1000.0);
        }
    }

    @Autowired
    private AdminService wdcAdminService;

    @Autowired
    private VergoedingFeestdagService vergoedingFeestdagService;

    @Autowired
    private OpdrachtService opdrachtService;

    private void test(int adminid, int pid, int opid, LocalDate datum) {
        Admin admin = wdcAdminService.getById(adminid);

        Opdracht opdracht = opdrachtService.getByPersoonOpdrachtNr(admin, pid, opid);

        List<VergoedingFeestDagResultaat> resultaat = vergoedingFeestdagService.rekenVergoedingFeestdag(admin, Lists.newArrayList(opdracht), datum);
        resultaat.forEach(r -> log.info(r.toString()));
    }

    private void testAll(int adminid, LocalDate datum) {
        Admin admin = wdcAdminService.getById(adminid);

        TemporalContext.getInstance().setActualInterval(new Month(datum));

        List<Opdracht> opdrachten = opdrachtService.findAll(admin);
        TemporalContext.getInstance().clearActualInterval();

        List<VergoedingFeestDagResultaat> resultaat = vergoedingFeestdagService.rekenVergoedingFeestdag(admin, opdrachten, datum);
        resultaat.forEach(r -> log.info(r.toString()));
    }

}
